-- ============================================================================
-- Quiz Seed: Acts — Part 1 (Chapters 1–6)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 1–3 ═══════════════

-- ═══ Acts Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 1, 'kids', 1, 'What did Jesus promise to send His disciples before He went to heaven?', 'The Holy Ghost', 'A new king', 'A box of gold', 'More food', 'a', 'Acts 1:8 — "But ye shall receive power, after that the Holy Ghost is come upon you."'),
('Acts', 1, 'kids', 2, 'How did Jesus go up to heaven?', 'A cloud received Him out of their sight', 'He walked away on a road', 'He rode a chariot of fire', 'He disappeared in a flash of light', 'a', 'Acts 1:9 — "And when he had spoken these things, while they beheld, he was taken up; and a cloud received him out of their sight."'),
('Acts', 1, 'kids', 3, 'Who was chosen to replace Judas as one of the twelve apostles?', 'Matthias', 'Paul', 'Barnabas', 'Timothy', 'a', 'Acts 1:26 — "And they gave forth their lots; and the lot fell upon Matthias; and he was numbered with the eleven apostles."'),
-- Teens
('Acts', 1, 'teens', 1, 'What did Jesus say the disciples would be when the Holy Ghost came upon them?', 'Witnesses unto Him in Jerusalem, Judaea, Samaria, and unto the uttermost part of the earth', 'Rulers of all the nations', 'Wealthy merchants in every city', 'Temple priests in Jerusalem', 'a', 'Acts 1:8 — "But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth."'),
('Acts', 1, 'teens', 2, 'What did the disciples ask Jesus before He ascended?', 'Lord, wilt thou at this time restore again the kingdom to Israel?', 'Will you destroy the Roman Empire now?', 'Should we build a new temple?', 'Can we go back to fishing?', 'a', 'Acts 1:6 — "When they therefore were come together, they asked of him, saying, Lord, wilt thou at this time restore again the kingdom to Israel?"'),
('Acts', 1, 'teens', 3, 'What did the two men in white apparel say to the disciples as they watched Jesus ascend?', 'This same Jesus shall so come in like manner as ye have seen him go into heaven', 'Jesus will never return to earth', 'You must climb up to heaven yourselves', 'Go immediately and tell the Romans', 'a', 'Acts 1:11 — "Ye men of Galilee, why stand ye gazing up into heaven? this same Jesus, which is taken up from you into heaven, shall so come in like manner as ye have seen him go into heaven."'),
('Acts', 1, 'teens', 4, 'How many days did Jesus show Himself alive after His resurrection before ascending?', 'Forty days, speaking of the things pertaining to the kingdom of God', 'Seven days', 'Three days', 'One hundred days', 'a', 'Acts 1:3 — "To whom also he shewed himself alive after his passion by many infallible proofs, being seen of them forty days, and speaking of the things pertaining to the kingdom of God."'),
('Acts', 1, 'teens', 5, 'What were the qualifications for the man chosen to replace Judas?', 'He must have been with the apostles from the baptism of John until the day Jesus was taken up, and be a witness of the resurrection', 'He must be from the tribe of Levi', 'He must have been born in Jerusalem', 'He must be able to perform miracles', 'a', 'Acts 1:21-22 — "Wherefore of these men which have companied with us all the time that the Lord Jesus went in and out among us, Beginning from the baptism of John, unto that same day that he was taken up from us, must one be ordained to be a witness with us of his resurrection."'),
-- Adults
('Acts', 1, 'adults', 1, 'How does Acts 1:8 function as a theological outline for the entire book of Acts?', 'It provides a geographic and missional outline: chapters 1-7 cover Jerusalem, 8-12 cover Judaea and Samaria, and 13-28 cover the mission to the uttermost part of the earth — the Spirit empowers witness that expands outward in concentric circles from Jerusalem to Rome', 'It only describes the first chapter', 'It is a summary of the Old Testament', 'It was added by a later editor', 'a', 'Acts 1:8 — "Ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth." This verse is the table of contents for Acts: Jerusalem (1-7), Judaea/Samaria (8-12), ends of the earth (13-28, culminating in Rome).'),
('Acts', 1, 'adults', 2, 'What is the significance of Jesus commanding the disciples to wait in Jerusalem rather than immediately beginning their mission?', 'The command to wait demonstrates that effective witness depends on divine empowerment, not human initiative — the disciples needed the Holy Spirit''s power before they could fulfil the Great Commission. Ministry flows from receiving, not from striving', 'Jesus wanted to delay the gospel', 'Jerusalem was the safest city', 'The disciples needed more education first', 'a', 'Acts 1:4-5 — "Wait for the promise of the Father... ye shall be baptized with the Holy Ghost not many days hence." The tarrying command teaches that spiritual power precedes spiritual work. The church''s first act is not action but prayer and waiting on God.'),
('Acts', 1, 'adults', 3, 'Why did Jesus redirect the disciples'' question about restoring the kingdom to Israel?', 'Jesus neither confirms nor denies a future restoration of Israel — He redirects from timing ("It is not for you to know the times or the seasons") to mission ("ye shall be witnesses"). The focus shifts from political speculation to Spirit-empowered witness, redefining the kingdom from national restoration to global proclamation', 'Jesus was avoiding their question because He did not know', 'The kingdom of Israel was permanently cancelled', 'Jesus agreed that the restoration would happen immediately', 'a', 'Acts 1:7-8 — "It is not for you to know the times or the seasons, which the Father hath put in his own power. But ye shall receive power..." Jesus does not deny a future kingdom but shifts the focus from eschatological timetables to present mission.'),
('Acts', 1, 'adults', 4, 'What is the theological significance of the Ascension in Luke-Acts?', 'The Ascension marks the transition from Jesus'' earthly ministry to His heavenly reign and the Spirit''s ministry through the church. It is the hinge between the Gospels and Acts — Jesus must depart bodily so the Spirit can come (John 16:7). It also affirms Jesus'' exaltation to the Father''s right hand and guarantees His visible return', 'The Ascension was only symbolic', 'Jesus simply disappeared forever', 'It has no theological importance', 'a', 'Acts 1:9-11 — The Ascension completes the incarnation narrative (birth → ministry → death → resurrection → ascension → session). It inaugurates Jesus'' heavenly intercession (Hebrews 7:25) and His sending of the Spirit (Acts 2:33). The promise of return "in like manner" grounds Christian hope.'),
('Acts', 1, 'adults', 5, 'What does the method of choosing Matthias (casting lots) reveal about the early church''s decision-making before Pentecost?', 'Casting lots was an accepted Old Testament method for discerning God''s will (Proverbs 16:33). The apostles prayed and then cast lots — combining prayer with an Old Testament practice. Notably, after Pentecost the church is never recorded using lots again, suggesting the Spirit''s indwelling presence replaced this method', 'Casting lots was a pagan practice the apostles should not have used', 'It was purely random with no divine involvement', 'This method continued throughout the book of Acts', 'a', 'Acts 1:24-26 — "They prayed, and said, Thou, Lord, which knowest the hearts of all men, shew whether of these two thou hast chosen... And the lot fell upon Matthias." Proverbs 16:33 says "The lot is cast into the lap; but the whole disposing thereof is of the LORD." After Pentecost, the Spirit guides directly.'),
('Acts', 1, 'adults', 6, 'How does Luke''s prologue in Acts 1:1-2 connect this book to his Gospel?', 'Luke calls his Gospel "the former treatise" about what Jesus "began both to do and teach" — implying that Acts records what the risen Jesus continues to do and teach through the Holy Spirit and the church. Acts is not a separate story but the continuation of Jesus'' work by other means', 'Acts has no connection to Luke''s Gospel', 'Luke did not write the Gospel of Luke', 'The prologue was added by another author', 'a', 'Acts 1:1 — "The former treatise have I made, O Theophilus, of all that Jesus began both to do and teach." The key word is "began" (erxato) — the Gospel records the beginning; Acts records the continuation through the Spirit-empowered church.'),
('Acts', 1, 'adults', 7, 'What is the significance of the disciples being gathered in the "upper room" for prayer?', 'The upper room connects to the Last Supper setting and establishes a pattern of communal prayer as the foundation for the church''s life. The 120 disciples (v.15) — including women and Jesus'' brothers — represent the nucleus of the church, united in prayer, awaiting the Spirit. Corporate prayer precedes Pentecost', 'The upper room was chosen for its large size only', 'Only the twelve apostles were present', 'It was a secret meeting to avoid the Romans', 'a', 'Acts 1:13-14 — "They went up into an upper room... These all continued with one accord in prayer and supplication, with the women, and Mary the mother of Jesus, and with his brethren." The emphasis on "one accord" (homothumadon) and persistent prayer sets the stage for Pentecost.'),
('Acts', 1, 'adults', 8, 'What does Peter''s speech about Judas (1:16-20) reveal about the early church''s understanding of Scripture and divine sovereignty?', 'Peter interprets Judas'' betrayal and death as fulfilment of Scripture (Psalms 69:25 and 109:8), showing the early church saw even acts of human treachery as within God''s sovereign plan. The Scripture "must needs have been fulfilled, which the Holy Ghost by the mouth of David spake" — divine foreknowledge does not excuse human guilt', 'Peter blamed God for Judas'' betrayal', 'Peter said Scripture had no relevance to current events', 'Judas'' replacement was unnecessary', 'a', 'Acts 1:16-20 — "This scripture must needs have been fulfilled, which the Holy Ghost by the mouth of David spake before concerning Judas." Peter reads the Psalms Christologically, seeing David''s words as prophetically fulfilled in Judas. Human responsibility and divine sovereignty coexist.');

-- ═══ Acts Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 2, 'kids', 1, 'What appeared on the disciples'' heads on the day of Pentecost?', 'Cloven tongues like as of fire', 'Golden crowns', 'Silver stars', 'White flowers', 'a', 'Acts 2:3 — "And there appeared unto them cloven tongues like as of fire, and it sat upon each of them."'),
('Acts', 2, 'kids', 2, 'What special thing could the disciples do after the Holy Ghost came upon them?', 'Speak in other languages so everyone could understand them', 'Fly through the air', 'Turn water into wine', 'Walk through walls', 'a', 'Acts 2:4 — "And they were all filled with the Holy Ghost, and began to speak with other tongues, as the Spirit gave them utterance."'),
('Acts', 2, 'kids', 3, 'How many people were baptised and added to the church on the day of Pentecost?', 'About three thousand souls', 'About one hundred people', 'About five hundred people', 'About ten thousand people', 'a', 'Acts 2:41 — "Then they that gladly received his word were baptized: and the same day there were added unto them about three thousand souls."'),
-- Teens
('Acts', 2, 'teens', 1, 'What Old Testament prophet did Peter quote to explain what was happening at Pentecost?', 'Joel — "And it shall come to pass in the last days, saith God, I will pour out of my Spirit upon all flesh"', 'Isaiah, who wrote about the suffering servant', 'Ezekiel, who saw the valley of dry bones', 'Daniel, who interpreted dreams', 'a', 'Acts 2:16-17 — "But this is that which was spoken by the prophet Joel; And it shall come to pass in the last days, saith God, I will pour out of my Spirit upon all flesh."'),
('Acts', 2, 'teens', 2, 'What did Peter boldly declare about Jesus to the crowd?', 'That God had made Jesus both Lord and Christ — the same Jesus whom they had crucified', 'That Jesus was merely a good teacher', 'That Jesus would return to destroy Jerusalem', 'That Jesus wanted them to rebel against Rome', 'a', 'Acts 2:36 — "Therefore let all the house of Israel know assuredly, that God hath made that same Jesus, whom ye have crucified, both Lord and Christ."'),
('Acts', 2, 'teens', 3, 'What did the people ask Peter after hearing his sermon?', 'Men and brethren, what shall we do?', 'How can we become rulers of Israel?', 'Where should we build a new temple?', 'Who should be our new king?', 'a', 'Acts 2:37 — "Now when they heard this, they were pricked in their heart, and said unto Peter and to the rest of the apostles, Men and brethren, what shall we do?"'),
('Acts', 2, 'teens', 4, 'What did Peter tell the people to do in response to the gospel?', 'Repent, and be baptised every one of you in the name of Jesus Christ for the remission of sins, and ye shall receive the gift of the Holy Ghost', 'Go home and think about it', 'Offer animal sacrifices in the temple', 'Join the Roman army to prove loyalty', 'a', 'Acts 2:38 — "Then Peter said unto them, Repent, and be baptized every one of you in the name of Jesus Christ for the remission of sins, and ye shall receive the gift of the Holy Ghost."'),
('Acts', 2, 'teens', 5, 'What four activities did the early church devote themselves to?', 'The apostles'' doctrine, fellowship, breaking of bread, and prayers', 'Trading, farming, building, and governing', 'Singing, dancing, feasting, and travelling', 'Debating, writing, teaching, and judging', 'a', 'Acts 2:42 — "And they continued stedfastly in the apostles'' doctrine and fellowship, and in breaking of bread, and in prayers."'),
-- Adults
('Acts', 2, 'adults', 1, 'What is the significance of Pentecost occurring on the Jewish feast of Shavuot (Feast of Weeks)?', 'Shavuot celebrated the giving of the Law at Sinai — the Spirit''s outpouring at Pentecost parallels and surpasses Sinai: where the Law was written on stone tablets, the Spirit now writes on hearts (Jeremiah 31:33, 2 Corinthians 3:3). The new covenant community is born on the anniversary of the old covenant''s inauguration', 'The date was purely coincidental', 'Pentecost has no connection to the Old Testament', 'Shavuot was only a harvest festival', 'a', 'Acts 2:1 — "When the day of Pentecost was fully come." Jewish tradition connected Shavuot with the Sinai theophany. The fire (Acts 2:3) and sound (2:2) echo Sinai (Exodus 19:16-18). Where Sinai gave the Law externally, Pentecost gives the Spirit internally.'),
('Acts', 2, 'adults', 2, 'How does the gift of tongues at Pentecost relate to the Tower of Babel narrative?', 'At Babel (Genesis 11), God confused languages to scatter rebellious humanity. At Pentecost, the Spirit enables communication across language barriers to unite people in the gospel. Pentecost is the reversal of Babel — where sin divided humanity by language, grace reunites humanity through the Spirit', 'Tongues and Babel are unrelated', 'Pentecost created new confusion like Babel', 'Only Hebrew was spoken at Pentecost', 'a', 'Acts 2:6-11 — People from every nation heard "the wonderful works of God" in their own tongues. The list of nations (vv.9-11) echoes Genesis 10''s Table of Nations. Babel scattered; Pentecost gathers. The curse of disunity begins to be reversed.'),
('Acts', 2, 'adults', 3, 'What does Peter''s sermon in Acts 2:14-36 reveal about early apostolic preaching (kerygma)?', 'The sermon contains core elements of the apostolic kerygma: the fulfilment of OT prophecy (Joel 2, Psalms 16 and 110), Jesus'' life/death/resurrection as historical events, God''s vindication of Jesus through resurrection, His exaltation to God''s right hand, and the call to repentance — Christological proclamation rooted in Scripture', 'Peter only shared personal feelings', 'The sermon had no Old Testament references', 'Peter focused on moral teaching only', 'a', 'Peter''s Pentecost sermon is the template for apostolic preaching: Scripture fulfilment (2:16-21,25-28,34-35), historical testimony (2:22), crucifixion (2:23), resurrection (2:24,32), exaltation (2:33-34), Christological conclusion (2:36), and call to respond (2:38).'),
('Acts', 2, 'adults', 4, 'What does Peter''s quotation of Psalm 16:10 ("thou wilt not leave my soul in hell, neither wilt thou suffer thine Holy One to see corruption") argue about David and Jesus?', 'Peter argues that David could not have been speaking about himself because David died, was buried, and his tomb was still present — therefore David, as a prophet, was speaking about the resurrection of Christ, whose body did not see corruption. The psalm is Christological prophecy, not autobiography', 'David was speaking about himself', 'The psalm has no messianic meaning', 'Peter misquoted the psalm', 'a', 'Acts 2:29-31 — "He is both dead and buried, and his sepulchre is with us unto this day. Therefore being a prophet... he seeing this before spake of the resurrection of Christ, that his soul was not left in hell, neither his flesh did see corruption." David''s own death proves the words transcend him.'),
('Acts', 2, 'adults', 5, 'How does Acts 2:42-47 function as a paradigm for church life?', 'It presents four pillars of church community: teaching (apostles'' doctrine), fellowship (koinonia — including sharing possessions), sacrament (breaking of bread), and prayer. This fourfold pattern combines theological instruction, relational unity, worship, and dependence on God as inseparable elements of authentic church life', 'It describes a temporary arrangement that ended quickly', 'Only the prayer element continued', 'These activities were optional', 'a', 'Acts 2:42-47 — The four activities (doctrine, fellowship, bread, prayers) form the DNA of the church. The result: "glad and sincere hearts, praising God, and having favour with all the people" (v.46-47). Luke presents this as the normative, Spirit-filled community.'),
('Acts', 2, 'adults', 6, 'What does "the promise is unto you, and to your children, and to all that are afar off" (2:39) reveal about the scope of the gospel?', 'The promise extends in three concentric circles: "you" (the present Jewish audience), "your children" (future generations), and "all that are afar off" (Gentiles — cf. Isaiah 57:19, Ephesians 2:13,17). Peter, perhaps unknowingly, announces the universal scope that will unfold through Acts', 'The promise was only for Peter''s audience that day', 'Only children were included', 'Those "afar off" means Jews in distant lands only', 'a', 'Acts 2:39 — "For the promise is unto you, and to your children, and to all that are afar off, even as many as the Lord our God shall call." "Afar off" echoes Isaiah 57:19 and anticipates the Gentile mission. The scope widens progressively throughout Acts.'),
('Acts', 2, 'adults', 7, 'What does the phrase "God hath made that same Jesus, whom ye have crucified, both Lord and Christ" (2:36) mean theologically?', 'Peter does not mean Jesus became Lord and Christ at the resurrection — He was always Lord. Rather, through the resurrection and exaltation God publicly vindicated and demonstrated Jesus to be what He always was. The resurrection is the declaration and enthronement, not the origin, of His lordship and messiahship', 'Jesus only became Lord after the resurrection', 'Jesus was made Christ by popular vote', 'The title "Lord" is merely honorific', 'a', 'Acts 2:36 — "God hath made" (epoiesen) means God has publicly established and demonstrated. The crucified one is the exalted one — the same Jesus. His resurrection and session at God''s right hand (v.33-34) publicly declare what was true from eternity.'),
('Acts', 2, 'adults', 8, 'What is the significance of the early believers having "all things common" (2:44)?', 'It was a voluntary, Spirit-motivated generosity — not compulsory communism. Believers sold possessions "as every man had need" (v.45), demonstrating that the Spirit creates radical generosity and economic solidarity. It reflects the Deuteronomy 15:4 ideal ("there shall be no poor among you") and the koinonia principle', 'It was mandated by Roman law', 'Private property was abolished permanently', 'Only leaders shared their possessions', 'a', 'Acts 2:44-45 — "All that believed were together, and had all things common; And sold their possessions and goods, and parted them to all men, as every man had need." This was voluntary (cf. 5:4 "was it not in thine own power?") and need-based, not ideological.');

-- ═══ Acts Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 3, 'kids', 1, 'What did Peter say to the lame man at the temple gate?', 'Silver and gold have I none; but such as I have give I thee: In the name of Jesus Christ of Nazareth rise up and walk', 'Here is some money for food', 'Go to the doctor for help', 'Wait here and someone will carry you', 'a', 'Acts 3:6 — "Then Peter said, Silver and gold have I none; but such as I have give I thee: In the name of Jesus Christ of Nazareth rise up and walk."'),
('Acts', 3, 'kids', 2, 'What did the lame man do after he was healed?', 'He entered the temple walking, leaping, and praising God', 'He quietly sat down inside the temple', 'He went home and went to sleep', 'He ran away from Peter and John', 'a', 'Acts 3:8 — "And he leaping up stood, and walked, and entered with them into the temple, walking, and leaping, and praising God."'),
('Acts', 3, 'kids', 3, 'How long had the man at the temple gate been lame?', 'Since he was born — he was over forty years old', 'For only one year', 'Since he was a teenager', 'For just a few days', 'a', 'Acts 3:2 and 4:22 — "A certain man lame from his mother''s womb was carried, whom they laid daily at the gate of the temple." Acts 4:22 adds "the man was above forty years old, on whom this miracle of healing was shewed."'),
-- Teens
('Acts', 3, 'teens', 1, 'Why did Peter tell the crowd not to look at him and John as though they had healed the man by their own power?', 'He wanted all glory to go to Jesus — it was faith in the name of Jesus Christ that had made the man whole, not any power belonging to Peter and John', 'He was being falsely modest', 'He wanted John to get the credit instead', 'He did not believe the healing was real', 'a', 'Acts 3:12,16 — "Why look ye so earnestly on us, as though by our own power or holiness we had made this man to walk?... His name through faith in his name hath made this man strong."'),
('Acts', 3, 'teens', 2, 'What did Peter call Jesus in his sermon after the healing?', 'The Holy One and the Just, the Prince of life, whom God hath raised from the dead', 'A great teacher of the law', 'A political rebel against Rome', 'An ordinary carpenter from Nazareth', 'a', 'Acts 3:14-15 — "But ye denied the Holy One and the Just, and desired a murderer to be granted unto you; And killed the Prince of life, whom God hath raised from the dead."'),
('Acts', 3, 'teens', 3, 'What did Peter say the people had done through ignorance?', 'They had killed the Prince of life, but God had foretold by all His prophets that Christ should suffer, and so it was fulfilled', 'They had built the temple in the wrong place', 'They had forgotten to keep the Sabbath', 'They had failed to pay their temple taxes', 'a', 'Acts 3:17-18 — "And now, brethren, I wot that through ignorance ye did it, as did also your rulers. But those things, which God before had shewed by the mouth of all his prophets, that Christ should suffer, he hath so fulfilled."'),
('Acts', 3, 'teens', 4, 'What did Peter urge the crowd to do?', 'Repent and be converted, that their sins may be blotted out, when the times of refreshing shall come from the presence of the Lord', 'Leave Jerusalem immediately', 'Offer more animal sacrifices', 'Start a rebellion against the Romans', 'a', 'Acts 3:19 — "Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord."'),
('Acts', 3, 'teens', 5, 'What prophecy from Moses did Peter quote about a future prophet?', 'A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you', 'A king shall come from Egypt to rule Israel', 'A priest shall arise who never dies', 'A warrior shall defeat all Israel''s enemies', 'a', 'Acts 3:22 — "For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you."'),
-- Adults
('Acts', 3, 'adults', 1, 'What does the healing at the Beautiful Gate demonstrate about the nature of apostolic ministry?', 'The apostles continue Jesus'' ministry of compassion and power — Peter''s words ("such as I have give I thee") show that the church''s true wealth is spiritual authority in Christ''s name, not material resources. The healing validates the apostolic message and demonstrates the risen Christ working through His church', 'Peter was showing off his personal power', 'Healings were only meant to attract crowds', 'The healing was purely symbolic', 'a', 'Acts 3:6,12,16 — Peter explicitly denies personal power and attributes the healing to "the name of Jesus Christ." The miracle functions as a sign (semeion) confirming the gospel message, just as Jesus'' miracles confirmed His identity.'),
('Acts', 3, 'adults', 2, 'What Christological titles does Peter use in his sermon, and what does each reveal?', 'Peter calls Jesus the "Holy One" (divine sanctity), the "Just" (moral perfection), the "Prince of life" (author/originator of life), God''s "servant" (Isaiah''s suffering servant), and a "prophet like Moses" (Deuteronomy 18:15) — together painting a comprehensive portrait of Jesus as holy, righteous, life-giving, prophetic, and God''s chosen servant', 'Peter uses no titles for Jesus', 'Only the title "teacher" is used', 'Peter calls Jesus a political leader', 'a', 'Acts 3:13-15,22 — "His servant Jesus" (v.13, echoing Isaiah 42:1), "the Holy One and the Just" (v.14), "the Prince of life" (v.15, archegos = pioneer/author), "a prophet like unto me" (v.22, Deuteronomy 18:15). Each title reveals a facet of Jesus'' identity.'),
('Acts', 3, 'adults', 3, 'What does the phrase "times of refreshing" and "times of restitution of all things" (3:19-21) refer to eschatologically?', 'The "times of refreshing" likely refers to the spiritual renewal available now through repentance, while the "restitution of all things" (apokatastasis panton) refers to the future restoration at Christ''s return — the cosmic renewal prophesied throughout the Old Testament, when heaven and earth are restored to their intended state', 'Both phrases refer to the same event', 'They describe only the fall of Jerusalem', 'Peter was speaking about political liberation', 'a', 'Acts 3:19-21 — "Times of refreshing shall come from the presence of the Lord; And he shall send Jesus Christ... Whom the heaven must receive until the times of restitution of all things." The "restitution" (apokatastasis) echoes prophetic hope (Isaiah 65:17, Romans 8:21) for cosmic renewal at the parousia.'),
('Acts', 3, 'adults', 4, 'How does Peter''s use of Deuteronomy 18:15-19 ("a prophet like unto Moses") function in his argument?', 'Peter identifies Jesus as the eschatological prophet Moses predicted — and warns that whoever does not hear this prophet "shall be destroyed from among the people." This transfers covenant allegiance from Moses to Jesus: to reject Jesus is not merely to reject a teacher but to cut oneself off from God''s covenant community', 'Peter was comparing himself to Moses', 'The passage is about Joshua, not Jesus', 'Deuteronomy 18 has no messianic application', 'a', 'Acts 3:22-23 — Peter quotes Deuteronomy 18:15,19 and adds the penalty from Leviticus 23:29. The "prophet like Moses" expectation was alive in Second Temple Judaism (cf. John 1:21,25; 6:14). Peter says that prophet has come — and obedience to Him is now the covenant requirement.'),
('Acts', 3, 'adults', 5, 'What does Peter mean by calling the Jews "children of the prophets, and of the covenant" (3:25)?', 'Peter affirms Israel''s covenant privileges — they are heirs of the Abrahamic promise. "Unto you first" (v.26) means the gospel comes to Israel first as a covenant priority, not because Gentiles are excluded. The Abrahamic covenant''s scope ("all kindreds of the earth shall be blessed") already contained the universal gospel', 'Peter was flattering the crowd', 'Only literal descendants of prophets were addressed', 'The covenant had been permanently revoked', 'a', 'Acts 3:25-26 — "Ye are the children of the prophets, and of the covenant which God made with our fathers, saying unto Abraham, And in thy seed shall all the kindreds of the earth be blessed. Unto you first God, having raised up his Son Jesus, sent him to bless you." Priority, not exclusivity.'),
('Acts', 3, 'adults', 6, 'How does Peter balance human responsibility and divine sovereignty in 3:13-18?', 'Peter holds both in tension: "ye delivered up... ye denied... ye killed" (human guilt, vv.13-15) and "God before had shewed by the mouth of all his prophets, that Christ should suffer, he hath so fulfilled" (divine plan, v.18). Human responsibility is not diminished by divine foreordination — both are simultaneously true', 'Peter blames only the Romans', 'Divine sovereignty removes human guilt', 'Peter says the crucifixion was an accident', 'a', 'Acts 3:13-18 — Peter does not soften the charge: "ye denied... ye killed the Prince of life" (vv.14-15). Yet he adds: "through ignorance ye did it" (v.17) and "God before had shewed... he hath so fulfilled" (v.18). Culpability and sovereignty coexist, as in Acts 2:23.'),
('Acts', 3, 'adults', 7, 'What is the significance of the phrase "his name through faith in his name" (3:16)?', 'The emphasis on "the name" reflects the Hebraic concept that a name carries the person''s authority and power. Faith in Jesus'' name means trusting in the person, authority, and redemptive work that the name represents. The double emphasis underscores that the healing''s source is Christ Himself, accessed through faith', 'The name is a magical formula', 'Any name would have the same effect', 'Peter was emphasising his own name', 'a', 'Acts 3:16 — "And his name through faith in his name hath made this man strong." In Hebrew thought, the name (shem) represents the person''s character and authority. "The name of Jesus" is shorthand for Jesus'' identity, power, and saving work — faith appropriates what the name represents.'),
('Acts', 3, 'adults', 8, 'How does Peter''s sermon in chapter 3 advance beyond his Pentecost sermon in chapter 2?', 'While both sermons proclaim Jesus'' death, resurrection, and exaltation, chapter 3 adds the themes of cosmic restoration (apokatastasis), the prophet-like-Moses typology, the Abrahamic covenant''s universal scope, and a stronger emphasis on Israel''s priority in receiving the gospel. It also addresses the practical implication of Christ''s power (the healing) and the call to repentance based on ignorance', 'It simply repeats the same points', 'Chapter 3 has less theological content', 'Peter contradicts his earlier sermon', 'a', 'Peter''s second sermon builds on the first: same core (death/resurrection/repentance) but expanded framework — Moses typology (3:22), Abrahamic covenant (3:25), "all the prophets from Samuel" (3:24), and the eschatological vision of "restitution of all things" (3:21). Luke shows the apostolic message deepening.');

-- ═══════════════ CHAPTERS 4–6 ═══════════════

-- ═══ Acts Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 4, 'kids', 1, 'What happened to Peter and John after they healed the lame man and preached?', 'They were arrested and put in prison by the rulers', 'They were given a reward', 'They were invited to a feast', 'They were made temple priests', 'a', 'Acts 4:3 — "And they laid hands on them, and put them in hold unto the next day: for it was now eventide."'),
('Acts', 4, 'kids', 2, 'What did Peter say is the only name by which we can be saved?', 'The name of Jesus Christ of Nazareth', 'The name of Moses', 'The name of the high priest', 'The name of Caesar', 'a', 'Acts 4:10,12 — "By the name of Jesus Christ of Nazareth... Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved."'),
('Acts', 4, 'kids', 3, 'What did the believers do when Peter and John told them what happened?', 'They prayed together and asked God for boldness', 'They ran away and hid', 'They gave up preaching', 'They complained and argued', 'a', 'Acts 4:24,29 — "They lifted up their voice to God with one accord... grant unto thy servants, that with all boldness they may speak thy word."'),
-- Teens
('Acts', 4, 'teens', 1, 'What was the reaction of the Jewish leaders when they saw Peter and John''s boldness?', 'They marvelled, and took knowledge of them, that they had been with Jesus — they were astonished that uneducated men spoke so powerfully', 'They immediately believed and were baptised', 'They ignored Peter and John completely', 'They praised them for their learning', 'a', 'Acts 4:13 — "Now when they saw the boldness of Peter and John, and perceived that they were unlearned and ignorant men, they marvelled; and they took knowledge of them, that they had been with Jesus."'),
('Acts', 4, 'teens', 2, 'What command did the rulers give Peter and John?', 'Not to speak at all nor teach in the name of Jesus', 'To leave Jerusalem and never return', 'To bring Jesus to the council', 'To pay a fine of one hundred pieces of silver', 'a', 'Acts 4:18 — "And they called them, and commanded them not to speak at all nor teach in the name of Jesus."'),
('Acts', 4, 'teens', 3, 'How did Peter and John respond to the command not to speak about Jesus?', 'Whether it be right in the sight of God to hearken unto you more than unto God, judge ye. For we cannot but speak the things which we have seen and heard', 'They agreed to stop preaching immediately', 'They promised to preach only in private', 'They asked for time to think about it', 'a', 'Acts 4:19-20 — "But Peter and John answered and said unto them, Whether it be right in the sight of God to hearken unto you more than unto God, judge ye. For we cannot but speak the things which we have seen and heard."'),
('Acts', 4, 'teens', 4, 'What happened when the believers prayed for boldness?', 'The place was shaken where they were assembled together, and they were all filled with the Holy Ghost and spoke the word of God with boldness', 'An angel appeared and gave them gold', 'A bright light filled the room', 'Nothing visible happened', 'a', 'Acts 4:31 — "And when they had prayed, the place was shaken where they were assembled together; and they were all filled with the Holy Ghost, and they spake the word of God with boldness."'),
('Acts', 4, 'teens', 5, 'What did Barnabas do to help the early church?', 'He sold his land and brought the money and laid it at the apostles'' feet', 'He built a new synagogue', 'He wrote letters to the Roman emperor', 'He started a school for children', 'a', 'Acts 4:36-37 — "And Joses, who by the apostles was surnamed Barnabas... Having land, sold it, and brought the money, and laid it at the apostles'' feet."'),
-- Adults
('Acts', 4, 'adults', 1, 'What does Acts 4:12 ("there is none other name under heaven given among men, whereby we must be saved") claim about the exclusivity of salvation through Christ?', 'It makes an absolute, universal claim: salvation is available through Jesus Christ alone — no other name, no other person, no other religion can save. "Under heaven" and "among men" make the scope cosmic and comprehensive. This is the most explicit statement of Christological exclusivism in Acts', 'It only means Jesus is one way among many', 'This applied only to first-century Jews', 'Peter was exaggerating for rhetorical effect', 'a', 'Acts 4:12 — "Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved." The negative ("neither... in any other") combined with the universal scope ("under heaven... among men") leaves no room for alternative paths to salvation.'),
('Acts', 4, 'adults', 2, 'How does the Sanhedrin''s dilemma in 4:16-17 illustrate the relationship between evidence and belief?', 'The Sanhedrin could not deny the miracle — "a notable miracle hath been done... and we cannot deny it" — yet they chose to suppress the truth rather than follow the evidence. This shows that unbelief is often not intellectual but volitional: the evidence was undeniable, but the will refused to submit', 'The Sanhedrin had legitimate reasons to doubt', 'The evidence was actually weak', 'The leaders simply needed more time', 'a', 'Acts 4:16-17 — "What shall we do to these men? for that indeed a notable miracle hath been done by them is manifest to all them that dwell in Jerusalem; and we cannot deny it." Despite irrefutable evidence, they chose suppression over submission — the will, not the mind, was the barrier.'),
('Acts', 4, 'adults', 3, 'What is the theological significance of the believers'' prayer quoting Psalm 2 (Acts 4:25-28)?', 'The prayer reads Psalm 2 as prophetically fulfilled in the crucifixion: Herod and Pilate are the "kings of the earth" and "rulers" who gathered against God''s "holy child Jesus." Yet the prayer affirms that these enemies did "whatsoever thy hand and thy counsel determined before to be done" — divine sovereignty encompassed even the cross', 'Psalm 2 was not about Jesus', 'The prayer contradicts Psalm 2', 'Only the political meaning was intended', 'a', 'Acts 4:25-28 — "Who by the mouth of thy servant David hast said, Why did the heathen rage... For of a truth against thy holy child Jesus... both Herod, and Pontius Pilate, with the Gentiles, and the people of Israel, were gathered together, For to do whatsoever thy hand and thy counsel determined before to be done."'),
('Acts', 4, 'adults', 4, 'What does the phrase "they had been with Jesus" (4:13) suggest about the source of spiritual authority?', 'The rulers recognised that Peter and John''s boldness came not from formal training ("unlearned and ignorant men" = no rabbinic education) but from their personal association with Jesus. True spiritual authority comes from relationship with Christ, not from academic credentials or institutional position', 'They recognised Peter''s seminary training', 'Being "with Jesus" meant physical proximity only', 'The rulers were complimenting their education', 'a', 'Acts 4:13 — "They took knowledge of them, that they had been with Jesus." The Greek word for "unlearned" (agrammatoi) means without rabbinic training, and "ignorant" (idiotai) means laymen. Yet they spoke with authority that surpassed the trained scholars — the difference was Jesus.'),
('Acts', 4, 'adults', 5, 'How does Peter''s boldness before the Sanhedrin contrast with his denial of Jesus before the crucifixion?', 'The transformation is dramatic: the same Peter who denied Jesus three times before a servant girl now boldly proclaims Christ before the supreme Jewish court. The difference is Pentecost — the Holy Spirit''s filling (4:8) transforms cowardice into courage. Peter is a living demonstration of the Spirit''s empowering work', 'Peter was always bold and never denied Jesus', 'His courage came from personal determination', 'The Sanhedrin was less intimidating than the servant girl', 'a', 'Acts 4:8 — "Then Peter, filled with the Holy Ghost, said unto them..." Compare with Luke 22:56-57 where Peter denied Jesus. The filling of the Spirit (Acts 2, repeated in 4:8,31) is the transforming agent. The same man, different power source.'),
('Acts', 4, 'adults', 6, 'What principle does Peter establish in 4:19-20 about civil disobedience?', 'Peter establishes that obedience to God takes absolute priority over obedience to human authority when they conflict — "Whether it be right in the sight of God to hearken unto you more than unto God, judge ye." This is not anarchy but principled, non-violent disobedience: they continue witnessing but do not resist arrest', 'Christians must always obey the government', 'Peter was calling for armed rebellion', 'The principle applies only to apostles', 'a', 'Acts 4:19-20 — Peter''s principle echoes Socrates'' "I shall obey God rather than you" (Apology 29d) but has deeper theological grounding. When human law contradicts divine command, God''s authority is supreme. The apostles model respectful but firm non-compliance.'),
('Acts', 4, 'adults', 7, 'What does the community''s sharing of possessions (4:32-35) reveal about the Holy Spirit''s effect on economics?', 'The Spirit created a community where "neither said any of them that ought of the things which he possessed was his own" — not abolishing private property but transforming the heart''s attachment to it. The result was "neither was there any among them that lacked" — the Spirit''s work produces radical generosity that eliminates poverty within the community', 'Forced redistribution was imposed', 'Only the apostles shared their goods', 'This was a Roman economic policy', 'a', 'Acts 4:32-35 — "The multitude of them that believed were of one heart and of one soul: neither said any of them that ought of the things which he possessed was his own." The grammar shows attitude ("said... was his own") not legislation. The Spirit transforms possessiveness into generosity.'),
('Acts', 4, 'adults', 8, 'What is the theological function of "the stone which the builders rejected" (4:11, quoting Psalm 118:22) in Peter''s defence?', 'Peter applies this psalm to the Sanhedrin directly — they are the "builders" (religious leaders responsible for constructing Israel''s spiritual house) who rejected Jesus, the cornerstone. Yet God made this rejected stone the head of the corner. The metaphor reverses the power dynamic: the builders'' rejection was overturned by God''s resurrection and exaltation', 'Peter was talking about literal construction', 'The builders were Roman architects', 'The stone refers to the temple itself', 'a', 'Acts 4:11 — "This is the stone which was set at nought of you builders, which is become the head of the corner." Jesus Himself applied Psalm 118:22 to the religious leaders (Matthew 21:42). Peter now applies it face-to-face: you rejected Him, God exalted Him. The reversal is complete.');

-- ═══ Acts Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 5, 'kids', 1, 'What happened to Ananias and Sapphira when they lied about the money they gave?', 'They both fell down dead because they had lied to God', 'They were put in prison', 'They were sent away from Jerusalem', 'Nothing happened to them', 'a', 'Acts 5:5,10 — "And Ananias hearing these words fell down, and gave up the ghost... Then fell she down straightway at his feet, and yielded up the ghost."'),
('Acts', 5, 'kids', 2, 'Who opened the prison doors for the apostles when they were locked up?', 'An angel of the Lord', 'The prison guard', 'A strong earthquake', 'Peter used a key', 'a', 'Acts 5:19 — "But the angel of the Lord by night opened the prison doors, and brought them forth."'),
('Acts', 5, 'kids', 3, 'What did the apostles do after the angel freed them from prison?', 'They went to the temple and started teaching the people about Jesus', 'They ran away from Jerusalem', 'They hid in the upper room', 'They went home to sleep', 'a', 'Acts 5:20-21 — "Go, stand and speak in the temple to the people all the words of this life. And when they heard that, they entered into the temple early in the morning, and taught."'),
-- Teens
('Acts', 5, 'teens', 1, 'What was the real sin of Ananias and Sapphira?', 'They lied to the Holy Ghost — they pretended to give the full price of their land while secretly keeping part for themselves', 'They stole money from the temple', 'They refused to help the poor', 'They worshipped false gods', 'a', 'Acts 5:3-4 — "Why hath Satan filled thine heart to lie to the Holy Ghost, and to keep back part of the price of the land? Whiles it remained, was it not thine own? and after it was sold, was it not in thine own power?"'),
('Acts', 5, 'teens', 2, 'What was Gamaliel''s advice to the Sanhedrin about the apostles?', 'Leave them alone — if this work is of men, it will come to nothing; but if it is of God, ye cannot overthrow it, lest ye be found fighting against God', 'Execute them immediately', 'Send them to prison for life', 'Force them to serve in the temple', 'a', 'Acts 5:38-39 — "Refrain from these men, and let them alone: for if this counsel or this work be of men, it will come to nought: But if it be of God, ye cannot overthrow it; lest haply ye be found even to fight against God."'),
('Acts', 5, 'teens', 3, 'What happened to the apostles before they were released from the council?', 'They were beaten and commanded not to speak in the name of Jesus', 'They were given money and thanked', 'They were simply warned and released', 'They were made honorary council members', 'a', 'Acts 5:40 — "And to him they agreed: and when they had called the apostles, and beaten them, they commanded that they should not speak in the name of Jesus, and let them go."'),
('Acts', 5, 'teens', 4, 'How did the apostles respond after being beaten?', 'They departed rejoicing that they were counted worthy to suffer shame for His name', 'They were angry and wanted revenge', 'They stopped preaching out of fear', 'They complained to the Roman governor', 'a', 'Acts 5:41 — "And they departed from the presence of the council, rejoicing that they were counted worthy to suffer shame for his name."'),
('Acts', 5, 'teens', 5, 'What answer did Peter give when the high priest said they were commanded not to teach in Jesus'' name?', 'We ought to obey God rather than men', 'We are sorry and will stop immediately', 'We did not know about the command', 'We will teach more quietly from now on', 'a', 'Acts 5:29 — "Then Peter and the other apostles answered and said, We ought to obey God rather than men."'),
-- Adults
('Acts', 5, 'adults', 1, 'What does the Ananias and Sapphira incident reveal about the Holy Spirit''s presence in the early church?', 'The severity of judgment reveals the Holy Spirit as a divine person who can be "lied to" (v.3) and "tempted" (v.9) — not an impersonal force. The Spirit''s presence made the church a sacred space where hypocrisy brought immediate divine discipline, paralleling Achan''s sin in Joshua 7 at the start of the conquest', 'The Holy Spirit is merely an influence', 'The incident was about tax evasion', 'Peter personally punished them', 'a', 'Acts 5:3-4,9 — "Why hath Satan filled thine heart to lie to the Holy Ghost?... thou hast not lied unto men, but unto God." Lying to the Spirit = lying to God. The Spirit is both personal (can be lied to) and divine (equated with God). The parallel with Achan (Joshua 7) is structural: both are first sins in a new community that require swift judgment to preserve holiness.'),
('Acts', 5, 'adults', 2, 'Why was the punishment of Ananias and Sapphira so severe?', 'Their sin was not withholding money (Peter said the property was theirs to keep) but the conspiracy to deceive the Spirit — introducing hypocrisy into the pure community. At the church''s foundational stage, unchecked deception would corrupt the body. The severity parallels Nadab and Abihu (Leviticus 10) — at covenant beginnings, God demonstrates His holiness dramatically', 'God was being cruel and unjust', 'Peter cursed them out of anger', 'It was a natural coincidence', 'a', 'Acts 5:4 — "Whiles it remained, was it not thine own?" The sin was not financial but spiritual: pretending to be what they were not. Leviticus 10:1-3 (Nadab/Abihu), Joshua 7 (Achan), and Acts 5 (Ananias/Sapphira) all occur at the start of a new era, establishing that God''s holiness cannot be trifled with.'),
('Acts', 5, 'adults', 3, 'What does Gamaliel''s speech (5:34-39) reveal about the Pharisaic approach to the Jesus movement?', 'Gamaliel, a respected Pharisee and Paul''s future teacher, advocates pragmatic restraint — let God judge the movement''s validity by its fruit. His advice reflects a theological principle (God will vindicate truth) but also reveals Pharisaic caution. However, his "wait and see" approach is not the same as faith — neutrality toward Christ is not the response Acts commends', 'Gamaliel was a secret Christian', 'His advice was the ideal response to the gospel', 'He was trying to protect the apostles because he believed', 'a', 'Acts 5:34-39 — Gamaliel cites Theudas and Judas of Galilee as failed movements. His logic: if it''s human, it will fail; if divine, you can''t stop it. While his advice providentially spares the apostles, Luke does not present neutrality as adequate — Acts calls for commitment, not fence-sitting.'),
('Acts', 5, 'adults', 4, 'How does Peter''s summary of the gospel in 5:30-32 encapsulate the apostolic message?', 'Peter''s speech contains all essential kerygmatic elements: God raised Jesus (resurrection), whom ye slew (crucifixion/human guilt), hanging on a tree (Deuteronomy 21:23 curse connection), God exalted Him as Prince and Saviour (exaltation), to give repentance and forgiveness of sins (salvation offered), and we are witnesses... and so is also the Holy Ghost (dual testimony)', 'Peter only mentioned the resurrection', 'The speech lacked any Old Testament references', 'Peter did not mention forgiveness', 'a', 'Acts 5:30-32 — "The God of our fathers raised up Jesus, whom ye slew and hanged on a tree. Him hath God exalted with his right hand to be a Prince and a Saviour, for to give repentance to Israel, and forgiveness of sins. And we are his witnesses... and so is also the Holy Ghost." A complete gospel summary.'),
('Acts', 5, 'adults', 5, 'What does "hanged on a tree" (5:30) signify in light of Deuteronomy 21:23?', 'By referencing "a tree" (xulon), Peter alludes to Deuteronomy 21:23 — "he that is hanged is accursed of God." This connects Christ''s crucifixion to the covenant curse, which Paul later develops fully (Galatians 3:13): Christ became a curse for us on the cross, bearing the covenant penalty that humanity deserved', 'It is simply a description of a wooden cross', 'Peter was speaking about a literal tree', 'The phrase has no Old Testament background', 'a', 'Acts 5:30 — "Whom ye slew and hanged on a tree." The word "tree" (xulon) rather than "cross" (stauros) deliberately echoes Deuteronomy 21:23 (LXX uses xulon). Peter implies that the cursed death was part of God''s redemptive plan — the curse became the means of blessing.'),
('Acts', 5, 'adults', 6, 'What does the apostles'' joy in suffering (5:41) reveal about the early Christian understanding of persecution?', 'Rejoicing in suffering reflects Jesus'' beatitude teaching (Matthew 5:11-12) now being lived out — persecution is counted an honour because it confirms their identification with Christ. Suffering "for his name" is not stoic endurance but active joy, because it validates their message and fellowship with the rejected Messiah', 'They were in shock and not thinking clearly', 'Joy in suffering is masochistic', 'They were pretending to be happy', 'a', 'Acts 5:41 — "Rejoicing that they were counted worthy to suffer shame for his name." This echoes Jesus'' words: "Blessed are ye, when men shall revile you... for my sake. Rejoice, and be exceeding glad" (Matthew 5:11-12). The early church saw persecution as a badge of honour.'),
('Acts', 5, 'adults', 7, 'What is the significance of "we ought to obey God rather than men" (5:29) as a repeated principle?', 'This is an intensification of 4:19 ("judge ye") — Peter now states it as a categorical imperative ("we ought," dei = divine necessity). The progression from respectful appeal (4:19) to firm declaration (5:29) shows the apostles growing bolder under pressure. The principle establishes that divine commands always supersede human authority', 'Peter was being disrespectful', 'This applies only in the first century', 'Peter was quoting a Roman philosopher', 'a', 'Acts 5:29 — "We ought to obey God rather than men." The Greek dei (it is necessary/one must) expresses divine compulsion. Compare 4:19 (courteous question) with 5:29 (categorical statement). Each confrontation with the Sanhedrin increases apostolic boldness — persecution refines rather than silences.'),
('Acts', 5, 'adults', 8, 'How does chapter 5 demonstrate the theme of unstoppable gospel advance?', 'Despite opposition (imprisonment, threats, beatings), the chapter ends with the apostles teaching and preaching "daily in the temple, and in every house" (v.42). Each attempt to silence the gospel accelerates it: prison leads to angelic deliverance, threats produce bolder witness, and beatings produce joy. Luke shows that human opposition cannot stop the Spirit-empowered mission', 'The gospel advance slowed after chapter 5', 'Opposition succeeded in silencing the apostles', 'The gospel only spread because of political support', 'a', 'Acts 5:42 — "And daily in the temple, and in every house, they ceased not to teach and preach Jesus Christ." The pattern: persecution → deliverance → continued proclamation → more persecution → more boldness. Luke demonstrates that the gospel is humanly unstoppable because it is divinely empowered.');

-- ═══ Acts Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 6, 'kids', 1, 'Why did the apostles choose seven men to help in the church?', 'To take care of giving food to the widows so the apostles could focus on prayer and preaching God''s word', 'To guard the temple gates', 'To collect money from all the cities', 'To write letters to the Roman emperor', 'a', 'Acts 6:2-4 — "It is not reason that we should leave the word of God, and serve tables. Wherefore, brethren, look ye out among you seven men... whom we may appoint over this business. But we will give ourselves continually to prayer, and to the ministry of the word."'),
('Acts', 6, 'kids', 2, 'What was the name of the man who was full of faith and power and did great wonders?', 'Stephen', 'Timothy', 'Barnabas', 'James', 'a', 'Acts 6:8 — "And Stephen, full of faith and power, did great wonders and miracles among the people."'),
('Acts', 6, 'kids', 3, 'What did Stephen''s face look like when he stood before the council?', 'Like the face of an angel', 'Like a warrior ready for battle', 'Very tired and weak', 'Red with anger', 'a', 'Acts 6:15 — "And all that sat in the council, looking stedfastly on him, saw his face as it had been the face of an angel."'),
-- Teens
('Acts', 6, 'teens', 1, 'What problem arose in the early church that led to the appointment of the seven?', 'The Grecian Jewish widows were being overlooked in the daily food distribution, causing murmuring against the Hebrew believers', 'There were too many people attending services', 'The temple was too small for the congregation', 'Some members refused to be baptised', 'a', 'Acts 6:1 — "And in those days, when the number of the disciples was multiplied, there arose a murmuring of the Grecians against the Hebrews, because their widows were neglected in the daily ministration."'),
('Acts', 6, 'teens', 2, 'What qualifications were required for the seven men chosen to serve?', 'Men of honest report, full of the Holy Ghost and wisdom', 'Men who were wealthy and well-connected', 'Men who had studied under famous rabbis', 'Men who were the oldest in the congregation', 'a', 'Acts 6:3 — "Wherefore, brethren, look ye out among you seven men of honest report, full of the Holy Ghost and wisdom, whom we may appoint over this business."'),
('Acts', 6, 'teens', 3, 'Why could the people who argued with Stephen not defeat him in debate?', 'They were not able to resist the wisdom and the spirit by which he spake', 'Stephen had a louder voice than everyone else', 'The Roman soldiers protected him', 'Stephen used tricks and dishonest arguments', 'a', 'Acts 6:10 — "And they were not able to resist the wisdom and the spirit by which he spake."'),
('Acts', 6, 'teens', 4, 'What false charge did Stephen''s enemies bring against him?', 'They accused him of speaking blasphemous words against Moses and against God — saying Jesus would destroy the temple and change the customs Moses delivered', 'They said he had stolen money from the temple', 'They accused him of being a Roman spy', 'They said he was performing magic by demonic power', 'a', 'Acts 6:11,13-14 — "We have heard him speak blasphemous words against Moses, and against God... This man ceaseth not to speak blasphemous words against this holy place, and the law: For we have heard him say, that this Jesus of Nazareth shall destroy this place, and shall change the customs which Moses delivered us."'),
('Acts', 6, 'teens', 5, 'Who was the first of the seven servants mentioned by name?', 'Stephen, a man full of faith and of the Holy Ghost', 'Philip, who later preached in Samaria', 'Nicolas, a proselyte of Antioch', 'Prochorus, who served the widows', 'a', 'Acts 6:5 — "And the saying pleased the whole multitude: and they chose Stephen, a man full of faith and of the Holy Ghost, and Philip, and Prochorus, and Nicanor, and Timon, and Parmenas, and Nicolas a proselyte of Antioch."'),
-- Adults
('Acts', 6, 'adults', 1, 'What does the Hellenist-Hebrew dispute reveal about the early church''s internal challenges?', 'The dispute shows that ethnic and cultural tensions existed within the earliest church — Hellenists (Greek-speaking Jews) and Hebrews (Aramaic-speaking Jews) had different cultural identities that could produce inequality. The church''s response — creating new leadership structures to address the problem — demonstrates both the reality of human sinfulness within the redeemed community and the Spirit-guided ability to adapt', 'The early church was perfectly harmonious', 'Only Gentiles caused problems', 'The dispute was about theological doctrine', 'a', 'Acts 6:1 — The "murmuring" (goggusmos, same word used of Israel in the wilderness) reveals real community friction. The Hellenist widows'' neglect was likely structural, not intentional, but it was real. The church''s adaptive response shows Spirit-led institutional innovation.'),
('Acts', 6, 'adults', 2, 'What is the significance of all seven chosen men having Greek names?', 'All seven names are Greek (Stephen, Philip, Prochorus, Nicanor, Timon, Parmenas, Nicolas), and Nicolas is identified as a Gentile proselyte. This suggests the church selected leaders from the aggrieved community to oversee the distribution — a remarkable act of trust and reconciliation. The majority placed the minority''s representatives in charge', 'Greek names were common for all Jews', 'It is purely coincidental', 'Only one name is Greek', 'a', 'Acts 6:5 — The Greek names suggest the seven were Hellenists, chosen to serve Hellenist widows. The Hebrew majority entrusted the food distribution to Hellenist leaders — putting the welfare of the marginalised community in the hands of people who understood their needs.'),
('Acts', 6, 'adults', 3, 'How does the apostles'' distinction between "serving tables" and "the ministry of the word" establish a principle for church governance?', 'The apostles do not denigrate practical service — they ensure it is done well by qualified, Spirit-filled people. The principle is specialisation, not hierarchy: the word ministry and the service ministry are both essential but require different gifts. This establishes the pattern of shared leadership with differentiated roles that respects both callings', 'Table service was considered inferior', 'Only apostles can serve communion', 'The seven were lower-class servants', 'a', 'Acts 6:2-4 — "It is not reason that we should leave the word of God, and serve tables." The apostles are not demeaning service but prioritising their calling. The seven are required to be "full of the Holy Ghost and wisdom" (v.3) — the same Spirit empowers both word ministry and service ministry.'),
('Acts', 6, 'adults', 4, 'What does Stephen''s ministry (teaching and miracles beyond table-serving) suggest about spiritual gifts and calling?', 'Stephen transcends his assigned role — appointed to serve tables but also performing wonders, miracles, and irresistible teaching. This shows that formal roles do not limit the Spirit''s gifting. Stephen''s ministry foreshadows the expansion of the gospel beyond Jerusalem and the Jewish establishment, as a Hellenist becomes the first martyr and theologian', 'Stephen overstepped his role and should have stayed quiet', 'Only apostles were allowed to teach', 'His miracles were performed without divine authority', 'a', 'Acts 6:8,10 — "Stephen, full of faith and power, did great wonders and miracles among the people... they were not able to resist the wisdom and the spirit by which he spake." The Spirit is not constrained by human organisational charts — Stephen''s calling exceeded his job description.'),
('Acts', 6, 'adults', 5, 'How do the false charges against Stephen (6:13-14) parallel the false charges against Jesus?', 'Both were accused of threatening to destroy the temple and changing Mosaic customs (cf. Matthew 26:61, Mark 14:58). The parallel is deliberate: Stephen follows in his Master''s footsteps. Like Jesus, Stephen faces a rigged trial with false witnesses, yet his face shines with divine glory (v.15, echoing Moses'' shining face in Exodus 34:29)', 'The charges against Stephen were entirely different', 'Stephen was accused of Roman crimes', 'There is no parallel with Jesus'' trial', 'a', 'Acts 6:13-14 — "This man ceaseth not to speak blasphemous words against this holy place, and the law." Compare Matthew 26:61: "This fellow said, I am able to destroy the temple of God." Luke draws deliberate parallels between Stephen''s trial and Jesus'' trial — the servant follows the master.'),
('Acts', 6, 'adults', 6, 'What is the significance of Stephen''s face appearing "as the face of an angel" (6:15)?', 'This echoes Moses'' shining face after encountering God (Exodus 34:29-35) — the divine glory radiates through Stephen, validating his testimony. The irony is that Stephen is accused of opposing Moses, yet he bears Moses'' own mark of divine encounter. God vindicates Stephen before the very court that condemns him', 'It was a figure of speech meaning he looked calm', 'Angels do not have visible faces', 'Stephen was wearing a costume', 'a', 'Acts 6:15 — "Saw his face as it had been the face of an angel." The allusion to Moses (Exodus 34:29) is deeply ironic: Stephen is charged with blasphemy against Moses, yet his face shines like Moses''. God''s glory on Stephen''s face is a visual rebuttal of the charges.'),
('Acts', 6, 'adults', 7, 'How does Acts 6 mark a transition point in the narrative structure of Acts?', 'Chapter 6 shifts the focus from the apostles in Jerusalem to the Hellenist leaders who will carry the gospel outward. Stephen''s speech and martyrdom (chapters 6-7) and Philip''s mission (chapter 8) fulfil Acts 1:8''s expansion beyond Jerusalem. The persecution triggered by Stephen scatters believers into Judaea and Samaria — opposition becomes the vehicle for mission', 'Chapter 6 is not a transition point', 'The focus remains on Jerusalem throughout Acts', 'Only Paul''s conversion marks a narrative shift', 'a', 'Acts 6:1-7 introduces Stephen and Philip — Hellenists who bridge the Jerusalem church and the wider mission. Stephen''s death (7:60) triggers the scattering (8:1) that fulfils Acts 1:8. The very persecution meant to stop the gospel becomes its accelerant.'),
('Acts', 6, 'adults', 8, 'What does the summary statement "the word of God increased; and the number of the disciples multiplied" (6:7) signify structurally in Acts?', 'Luke uses progress reports at key junctures (6:7, 9:31, 12:24, 16:5, 19:20, 28:31) to mark the gospel''s advance despite opposition. Each summary shows the word growing after a period of challenge. Acts 6:7 is particularly striking: even "a great company of the priests were obedient to the faith" — the gospel penetrates the very institution opposing it', 'It is a minor, insignificant detail', 'The growth stopped after this verse', 'Only Gentiles were becoming disciples', 'a', 'Acts 6:7 — "And the word of God increased; and the number of the disciples multiplied in Jerusalem greatly; and a great company of the priests were obedient to the faith." Luke''s progress reports structure Acts into panels of opposition → growth. Priestly conversions represent the gospel infiltrating its own persecuting institution.');
